// Cloudflare Worker for asset optimization

addEventListener('fetch', event => {
  event.respondWith(handleRequest(event.request))
})

async function handleRequest(request) {
  const url = new URL(request.url)

  // Image optimization
  if (url.pathname.match(/\.(jpg|jpeg|png|webp)$/)) {
    return fetch(request, {
      cf: {
        image: {
          format: 'webp',
          quality: 85,
          width: getOptimalWidth(request.headers.get('User-Agent'))
        }
      }
    })
  }

  // CSS/JS optimization
  if (url.pathname.match(/\.(css|js)$/)) {
    const response = await fetch(request)
    let content = await response.text()

    // Add compression headers
    const optimizedResponse = new Response(content, {
      status: response.status,
      statusText: response.statusText,
      headers: {
        ...response.headers,
        'Cache-Control': 'public, max-age=31536000, immutable',
        'Content-Encoding': 'br'
      }
    })

    return optimizedResponse
  }

  return fetch(request)
}

function getOptimalWidth(userAgent) {
  if (userAgent && userAgent.includes('Mobile')) {
    return 768
  }
  return 1920
}

