// Cloudflare Worker for API rate limiting

addEventListener('fetch', event => {
  event.respondWith(handleRequest(event.request))
})

async function handleRequest(request) {
  const url = new URL(request.url)
  const clientIP = request.headers.get('CF-Connecting-IP')
  const userAgent = request.headers.get('User-Agent')

  // Skip rate limiting for health checks
  if (url.pathname === '/health' || url.pathname.includes('/health')) {
    return fetch(request)
  }

  // Different limits for different endpoints
  const rateLimits = {
    '/api/v1/auth/': { requests: 10, window: 300 }, // 10 requests per 5 minutes
    '/api/v1/translation/': { requests: 50, window: 3600 }, // 50 per hour
    '/api/v1/export/': { requests: 100, window: 3600 }, // 100 per hour
    'default': { requests: 1000, window: 3600 } // 1000 per hour default
  }

  let limit = rateLimits.default
  for (const [path, pathLimit] of Object.entries(rateLimits)) {
    if (path !== 'default' && url.pathname.startsWith(path)) {
      limit = pathLimit
      break
    }
  }

  const key = `rate_limit:${clientIP}:${url.pathname.split('/')[1]}`
  const current = await RATE_LIMIT_STORE.get(key)

  if (current && parseInt(current) >= limit.requests) {
    return new Response(
      JSON.stringify({ error: 'Rate limit exceeded', retryAfter: limit.window }),
      { 
        status: 429,
        headers: {
          'Content-Type': 'application/json',
          'Retry-After': limit.window.toString(),
          'X-RateLimit-Limit': limit.requests.toString(),
          'X-RateLimit-Remaining': '0',
          'X-RateLimit-Reset': (Date.now() + limit.window * 1000).toString()
        }
      }
    )
  }

  // Increment counter
  const newCount = current ? parseInt(current) + 1 : 1
  await RATE_LIMIT_STORE.put(key, newCount.toString(), { expirationTtl: limit.window })

  // Add rate limit headers to response
  const response = await fetch(request)
  const modifiedResponse = new Response(response.body, {
    status: response.status,
    statusText: response.statusText,
    headers: {
      ...response.headers,
      'X-RateLimit-Limit': limit.requests.toString(),
      'X-RateLimit-Remaining': Math.max(0, limit.requests - newCount).toString(),
      'X-RateLimit-Reset': (Date.now() + limit.window * 1000).toString()
    }
  })

  return modifiedResponse
}
